import { hasPermissionCode } from '../utils/erpPermissionCode';

const APP = 'erp-hr';

function hrResource(resource: string) {
  const base = `${APP}:${resource}`;
  const canRead = hasPermissionCode(`${base}:read`);
  const canWrite = hasPermissionCode(`${base}:write`);
  return {
    canRead,
    canWrite,
    canCreate: canWrite,
    canUpdate: canWrite,
    canDelete: hasPermissionCode(`${base}:delete`) || canWrite,
  };
}

/** Danh mục nhân viên — `/ns/nhan-vien` */
export function useHrEmployeePermissions() {
  return hrResource('hr:employees');
}

/** Chấm công — `/ns/cham-cong` */
export function useHrAttendancePermissions() {
  return hrResource('hr:attendance');
}

/** Sổ sản lượng khoán — `/ns/so-luong-khoan` */
export function useHrPieceRateLedgerPermissions() {
  return hrResource('hr:piece-rate-ledger');
}

/** Ca làm việc — `/ns/ca-lam-viec` */
export function useHrWorkShiftPermissions() {
  return hrResource('hr:work-shifts');
}

/** Bảng lương (period job) — `/ns/bang-luong` · `erp-form-toolbar-permissions.md` § Tính toán */
export function useHrPayrollPermissions() {
  const base = `${APP}:hr:payroll`;
  return {
    canRead: hasPermissionCode(`${base}:read`),
    canRun: hasPermissionCode(`${base}:run`),
    canPost: hasPermissionCode(`${base}:post`),
  };
}
